            <a
              className="flex items-center gap-2 hover:opacity-60"
              href={whatsappUrl}
              rel="noopener noreferrer"
              target="_blank"
            >
              <span className="hidden xl:inline">Text Us</span>
              <Image
                alt="WhatsApp"
                height={20}
                src="/new-design-images/icons/whatsup.svg"
                width={20}
              />
            </a>

            <Link
              className="whitespace-nowrap rounded bg-[#000E65] px-4 py-2 font-medium text-[12px] text-white transition-colors hover:bg-blue-900"
              href={APP_ROUTES.BUYBACK_REQUESTS.CREATE}
            >
              Start with a Quote
            </Link>

            {isAuthenticated ? (
              <div className="flex items-center gap-4">
                <NotificationBadge className="cursor-pointer">
                  <BellIcon
                    aria-label="Notifications"
                    className={isTransparent ? "text-white" : "text-foreground"}
                    size={24}
                  />
                </NotificationBadge>
                <div
                  className={cn(
                    "h-8 w-[1px]",
                    isTransparent ? "bg-white/30" : "bg-[#D6D3D1]",
                  )}
                />
                <DropdownMenu>
                  <DropdownMenuTrigger asChild>
                    <button
                      aria-label="User menu"
                      className="cursor-pointer overflow-hidden rounded-[4px] border border-transparent transition-colors hover:border-border focus:outline-none"
                      type="button"
                    >
                      <Image
                        alt="User Profile"
                        className="object-cover"
                        height={36}
                        src={
                          avatarSrc ?? "/new-design-images/avatar-example.png"
                        }
                        width={36}
                      />
                    </button>
                  </DropdownMenuTrigger>
                  <DropdownMenuContent
                    align="end"
                    className="w-[220px] rounded-xl border border-[#D6D3D1] bg-[#F5F3EF] p-1 shadow-[0px_4px_16px_rgba(0,0,0,0.08)]"
                    sideOffset={8}
                  >
                    <DropdownMenuItem asChild>
                      <Link
                        className="flex cursor-pointer items-center gap-3 rounded-lg px-3 py-2.5 font-new-sans text-[#44403C] text-sm hover:bg-[#EDE9E3] focus:bg-[#EDE9E3]"
                        href={APP_ROUTES.PROFILE}
                      >
                        <CircleUserRound
                          className="shrink-0 text-[#44403C]"
                          size={16}
                        />
                        Profile Settings
                      </Link>
                    </DropdownMenuItem>
                    <DropdownMenuItem asChild>
                      <Link
                        className="flex cursor-pointer items-center gap-3 rounded-lg px-3 py-2.5 font-new-sans text-[#44403C] text-sm hover:bg-[#EDE9E3] focus:bg-[#EDE9E3]"
                        href={APP_ROUTES.WALLET.ROOT}
                      >
                        <InboxIcon
                          className="shrink-0 text-[#44403C]"
                          size={16}
                        />
                        Accounts & Wallets
                      </Link>
                    </DropdownMenuItem>
                    <DropdownMenuItem asChild>
                      <Link
                        className="flex cursor-pointer items-center gap-3 rounded-lg px-3 py-2.5 font-new-sans text-[#44403C] text-sm hover:bg-[#EDE9E3] focus:bg-[#EDE9E3]"
                        href={APP_ROUTES.WALLET.PAYMENT_HISTORY}
                      >
                        <ScrollTextIcon
                          className="shrink-0 text-[#44403C]"
                          size={16}
                        />
                        Transaction History
                      </Link>
                    </DropdownMenuItem>
                    <DropdownMenuSeparator className="my-1 bg-[#D6D3D1]" />
                    <DropdownMenuItem
                      className="flex cursor-pointer items-center gap-3 rounded-lg px-3 py-2.5 font-new-sans text-[#44403C] text-sm hover:bg-[#EDE9E3] focus:bg-[#EDE9E3]"
                      onClick={handleLogout}
                    >
                      <LogOutIcon
                        className="shrink-0 text-[#44403C]"
                        size={16}
                      />
                      Logout
                    </DropdownMenuItem>
                  </DropdownMenuContent>
                </DropdownMenu>
              </div>
            ) : (
              <div className="flex items-center gap-3">
                <Link
                  className="hover:opacity-60"
                  href={APP_ROUTES.AUTH.SIGN_IN}
                >
                  Login
                </Link>
                <div className="h-4 w-[1px] bg-black/10" />
                <Link
                  className="hover:opacity-60"
                  href={APP_ROUTES.AUTH.REGISTER}
                >
                  Register
                </Link>
              </div>
            )}
          </div>
        </div>

        {/* --- Mobile Version --- */}
        <div className="flex items-center justify-between lg:hidden">
          <MobileMenu isAuthenticated={isAuthenticated} />

          <Logo className="h-6 w-32" invert={isTransparent} />

          <div className="flex items-center gap-3">
            <a
              aria-label="Contact on WhatsApp"
              className="hover:opacity-60"
              href={whatsappUrl}
              rel="noopener noreferrer"
              target="_blank"
            >
              <Image
                alt=""
                height={22}
                src="/new-design-images/icons/whatsup.svg"
                width={22}
              />
            </a>
            {isAuthenticated ? (
              <NotificationBadge>
                <BellIcon aria-label="Notifications" size={22} />
              </NotificationBadge>
            ) : (
              <Link className="text-md" href={APP_ROUTES.AUTH.SIGN_IN}>
                Login
              </Link>
            )}
          </div>
        </div>
      </div>
    </header>
  );
};

const Logo = ({
  className,
  invert,
}: {
  className: string;
  invert?: boolean;
